1. 
{code:title=RollingLevelDBTimelineStore#putEntities}
  // write entity marker
  // ... ignore code to prepare markerKey
  byte[] markerValue = writeReverseOrderedLong(startAndInsertTime
      .insertTime);
  writeBatch.put(markerKey, markerValue);
{code}
is changed to 
{code}
