                key = iterator.peekNext().getKey();

             // BUGFIX code block
               iterator.next();
                if (!prefixMatches(firstKey, kp.getOffset(), key)) {
                  break;
                }
              }
              continue;
            }
          }
{code}
change to
{code}
if (fromTs != null) {
            long insertTime = readReverseOrderedLong(iterator.peekNext()
                .getValue(), 0);
            if (insertTime > fromTs) {
              byte[] firstKey = key;
              while (iterator.hasNext()) {
                key = iterator.peekNext().getKey();

                // BUGFIX code block
                if (!prefixMatches(firstKey, kp.getOffset(), key)) {
                  break;
                }
                iterator.next();
              }
              continue;
            }
          }
{code}

